/**
 * Gate Runtime
 * 
 * Production gate system that controls access to gated content (price, brochure).
 * Uses localStorage for persistence and reuses the existing condition evaluator
 * from preview-runtime to drive data-dr-show-when/hide-when/effect-when attributes.
 */

interface GateConfig {
  sectionId: string;
  token: string;
  endpoint: string;
  anonKey: string;
}

type GateState = 'locked' | 'modal' | 'unlocked';

class GateRuntime {
  private config: GateConfig;
  private state: GateState = 'locked';
  private storageKey: string;
  private pendingDownload: string | null = null;

  constructor(config: GateConfig) {
    this.config = config;
    this.storageKey = `dlr_gate_${config.token}`;
    this.init();
  }

  private init() {
    // Check localStorage for existing unlock
    const stored = localStorage.getItem(this.storageKey);
    if (stored === 'unlocked') {
      this.state = 'unlocked';
    }

    // Apply initial state
    this.applyState();

    // Intercept brochure link clicks
    this.setupBrochureInterception();

    // Expose API
    (window as any).dlrGate = {
      open: (callback?: () => void) => this.open(callback),
      unlock: () => this.unlock(),
      isUnlocked: () => this.isUnlocked(),
    };
  }

  private applyState() {
    // Update section data to trigger condition evaluation
    // In production, we need to manually trigger the data-dr-show-when/hide-when/effect-when logic
    
    // Update the section's previewState in the DOM
    const sectionEl = document.querySelector(`[data-dr-section="${this.config.sectionId}"]`);
    if (!sectionEl) return;

    // Store state as data attribute for condition evaluation
    sectionEl.setAttribute('data-gate-state', this.state);

    // Manually evaluate all conditions for this section
    this.evaluateConditions();
  }

  private evaluateConditions() {
    // Find all elements with data-dr-show-when, data-dr-hide-when, data-dr-effect-when
    const sectionId = this.config.sectionId;
    const state = this.state;

    // Show/hide elements based on previewState
    document.querySelectorAll('[data-dr-show-when], [data-dr-hide-when], [data-dr-effect-when]').forEach((el) => {
      const htmlEl = el as HTMLElement;
      
      // Show-when
      const showWhen = htmlEl.getAttribute('data-dr-show-when');
      if (showWhen) {
        const conditions = showWhen.split('|');
        const shouldShow = conditions.some(cond => {
          const match = cond.match(/^([^.]+)\.previewState=(.+)$/);
          if (match && match[1] === sectionId) {
            return match[2] === state;
          }
          return false;
        });
        htmlEl.style.display = shouldShow ? '' : 'none';
      }

      // Hide-when
      const hideWhen = htmlEl.getAttribute('data-dr-hide-when');
      if (hideWhen) {
        const conditions = hideWhen.split('|');
        const shouldHide = conditions.some(cond => {
          const match = cond.match(/^([^.]+)\.previewState=(.+)$/);
          if (match && match[1] === sectionId) {
            return match[2] === state;
          }
          return false;
        });
        htmlEl.style.display = shouldHide ? 'none' : '';
      }

      // Effect-when
      const effectWhen = htmlEl.getAttribute('data-dr-effect-when');
      const effect = htmlEl.getAttribute('data-dr-effect');
      if (effectWhen && effect) {
        const conditions = effectWhen.split('|');
        const shouldApply = conditions.some(cond => {
          const match = cond.match(/^([^.]+)\.previewState=(.+)$/);
          if (match && match[1] === sectionId) {
            return match[2] === state;
          }
          return false;
        });
        
        if (shouldApply) {
          // Apply the effect styles
          const styles = effect.split(';').filter(s => s.trim());
          styles.forEach(style => {
            const [prop, value] = style.split(':').map(s => s.trim());
            if (prop && value) {
              htmlEl.style.setProperty(prop, value);
            }
          });
        } else {
          // Remove the effect styles
          const styles = effect.split(';').filter(s => s.trim());
          styles.forEach(style => {
            const [prop] = style.split(':').map(s => s.trim());
            if (prop) {
              htmlEl.style.removeProperty(prop);
            }
          });
        }
      }
    });
  }

  private setupBrochureInterception() {
    document.addEventListener('click', (e) => {
      const target = e.target as HTMLElement;
      const link = target.closest('[data-brochure-link]') as HTMLAnchorElement;
      
      if (link && this.state !== 'unlocked') {
        e.preventDefault();
        e.stopPropagation();
        
        // Store the download URL
        this.pendingDownload = link.href;
        
        // Open the gate
        this.open();
      }
    }, true); // Use capture phase to intercept before other handlers
  }

  public open(callback?: () => void) {
    if (this.state === 'unlocked') {
      callback?.();
      return;
    }

    this.state = 'modal';
    this.applyState();
    
    if (callback) {
      callback();
    }
  }

  public unlock() {
    this.state = 'unlocked';
    localStorage.setItem(this.storageKey, 'unlocked');
    this.applyState();

    // If there's a pending download, trigger it immediately
    if (this.pendingDownload) {
      // Use window.location.href instead of link.click() for mobile Safari compatibility
      window.location.href = this.pendingDownload;
      this.pendingDownload = null;
    }
  }

  public isUnlocked(): boolean {
    return this.state === 'unlocked';
  }
}

// Initialize when DOM is ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', () => {
    if ((window as any).__DLR) {
      new GateRuntime((window as any).__DLR);
    }
  });
} else {
  if ((window as any).__DLR) {
    new GateRuntime((window as any).__DLR);
  }
}
